# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import redirect, url_for

def login_redirect(username):
    user = User.query.filter_by(username=username).first()
    if user:
        # Login successful, redirect to the requested page or default page
        return redirect(url_for('dashboard'))
    else:
        # Invalid username or password, display an error message
        return 'Invalid credentials', 401

def login_redirect_url(username, next_page=None):
    user = User.query.filter_by(username=username).first()
    if user:
        if next_page:
            return redirect(next_page)
        else:
            return redirect(url_for('dashboard'))
    else:
        # Invalid username or password, display an error message
        return 'Invalid credentials', 401